PRAGMA encoding = 'UTF-8';
DROP TABLE IF EXISTS idioms;

CREATE TABLE idioms (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    word TEXT NOT NULL UNIQUE,
    pinyin TEXT NOT NULL,
    meaning TEXT NOT NULL,
    origin TEXT NOT NULL,
    story TEXT NOT NULL,
    example TEXT NOT NULL,
    rare_level TEXT NOT NULL,
    tags TEXT NOT NULL
);

CREATE INDEX idx_idioms_word ON idioms(word);
CREATE INDEX idx_idioms_pinyin ON idioms(pinyin);
CREATE INDEX idx_idioms_rare_level ON idioms(rare_level);

BEGIN TRANSACTION;


COMMIT;
