INSERT INTO idioms (word, pinyin, meaning, origin, story, example, rare_level, tags) VALUES
('画蛇添足','hua she tian zu','画好蛇后又添上脚，比喻多此一举，反把事情弄坏。','《战国策·齐策二》','楚国有人比赛画蛇，先画成的人又给蛇添脚，结果失去酒。','方案已经完整，再加这些限制就是画蛇添足。','常用','寓言,战国,做事'),
('守株待兔','shou zhu dai tu','比喻不主动努力，只想侥幸获得成功。','《韩非子·五蠹》','宋国农夫偶然捡到撞树而死的兔子，便天天守着树等兔。','市场不会自己送上门，守株待兔只会错过机会。','常用','寓言,韩非子,勤奋'),
('亡羊补牢','wang yang bu lao','羊丢了再修羊圈，比喻出错后及时补救还不算晚。','《战国策·楚策四》','有人丢羊后修补破洞，避免继续损失。','这次线上问题暴露后，亡羊补牢也要把监控补起来。','常用','寓言,补救,管理'),
('掩耳盗铃','yan er dao ling','捂住自己的耳朵偷铃，比喻自欺欺人。','《吕氏春秋·自知》','盗铃者以为自己听不见铃声，别人也听不见。','把错误日志删掉并不能解决问题，这是掩耳盗铃。','常用','寓言,自欺,错误'),
('刻舟求剑','ke zhou qiu jian','在船上刻记号找落水的剑，比喻拘泥成法，不知变化。','《吕氏春秋·察今》','楚人剑落水后在船边刻痕，船走后仍按痕找剑。','需求已经变了，还按旧方案做就是刻舟求剑。','常用','寓言,变化,方法'),
('滥竽充数','lan yu chong shu','不会吹竽却混在队伍里凑数，比喻没有本领的人冒充有本领。','《韩非子·内储说上》','南郭先生混在齐宣王乐队中，独奏时只好逃走。','团队协作要靠真实能力，不能滥竽充数。','常用','寓言,能力,诚信'),
('井底之蛙','jing di zhi wa','井底的青蛙只能看见小片天空，比喻见识狭窄。','《庄子·秋水》','井蛙和海鳖谈天地，因视野太小无法理解大海。','只看一个市场就下结论，难免成了井底之蛙。','常用','寓言,视野,庄子'),
('自相矛盾','zi xiang mao dun','自己的说法前后抵触。','《韩非子·难一》','卖矛与盾的人同时夸矛无不穿、盾无不陷，被问后无法回答。','这份文档前后自相矛盾，需要重新梳理。','常用','逻辑,韩非子,表达'),
('杯弓蛇影','bei gong she ying','把杯中的弓影误认为蛇，比喻疑神疑鬼。','《晋书·乐广传》','客人误把酒杯中的弓影当蛇，因恐惧生病。','一次失败后就不敢尝试，是杯弓蛇影。','常用','心理,晋书,误会'),
('狐假虎威','hu jia hu wei','狐狸借老虎的威风吓唬百兽，比喻仗势欺人。','《战国策·楚策一》','狐狸被虎抓住后骗虎同行，让百兽以为怕的是狐狸。','他只是狐假虎威，真正的决策权不在他手里。','常用','寓言,权势,战国'),
('邯郸学步','han dan xue bu','模仿别人不成，反而丢掉自己的本领。','《庄子·秋水》','燕国少年到邯郸学走路，没学会还忘了原本走法。','产品可以借鉴竞品，但不能邯郸学步。','常用','模仿,庄子,学习'),
('叶公好龙','ye gong hao long','表面爱好某物，实际并不真喜欢。','《新序·杂事》','叶公家中到处画龙，真龙来访时却吓得逃走。','他说喜欢开源，却从不读代码，近似叶公好龙。','常用','态度,诚信,故事'),
('拔苗助长','ba miao zhu zhang','把苗拔高帮助生长，比喻急于求成反而坏事。','《孟子·公孙丑上》','宋人拔高禾苗，回家自称助长，结果禾苗枯死。','学习不能拔苗助长，基础要一步步补。','常用','寓言,成长,孟子'),
('买椟还珠','mai du huan zhu','买下装珠子的盒子却退还珠子，比喻取舍不当。','《韩非子·外储说左上》','楚人卖珠，郑人看中精美盒子而不要珍珠。','只追求页面动画却忽略核心功能，是买椟还珠。','常用','取舍,价值,韩非子'),
('南辕北辙','nan yuan bei zhe','车辕向南车轮向北，比喻行动和目标相反。','《战国策·魏策四》','有人想去楚国却向北走，条件越好离目标越远。','目标是降本，却不断增加复杂服务，已经南辕北辙。','常用','方向,目标,战国'),
('班门弄斧','ban men nong fu','在鲁班门前舞弄斧头，比喻在行家面前卖弄本领。','唐代柳宗元相关诗文典故','后人以鲁班为木匠祖师，在其门前弄斧显得不自量力。','在专家面前讲基础概念，要避免班门弄斧。','常用','谦虚,技艺,表达'),
('胸有成竹','xiong you cheng zhu','画竹前心中已有完整竹形，比喻做事前已有成熟打算。','宋代苏轼文与文同画竹典故','文同画竹前观察充分，下笔时胸中已有竹。','这次发布计划他胸有成竹，风险点都列清楚了。','常用','计划,艺术,宋代'),
('入木三分','ru mu san fen','笔力深入木板三分，比喻书法遒劲或见解深刻。','唐代张怀瓘《书断》','王羲之书写木板，工人削板发现墨迹深入木中。','这篇复盘入木三分，把根因讲透了。','常用','书法,见解,王羲之'),
('三顾茅庐','san gu mao lu','多次诚心拜访贤才，比喻真诚邀请。','《三国志》裴松之注引《出师表》相关记载','刘备三次到草庐拜访诸葛亮，请其出山辅佐。','公司三顾茅庐，终于请到这位架构师。','常用','三国,诚意,人才'),
('完璧归赵','wan bi gui zhao','把和氏璧完整带回赵国，比喻原物完整归还。','《史记·廉颇蔺相如列传》','蔺相如识破秦王夺璧意图，机智保全和氏璧。','借用的设备已经完璧归赵。','常用','史记,诚信,外交'),
('负荆请罪','fu jing qing zui','背着荆条请求责罚，比喻主动认错赔罪。','《史记·廉颇蔺相如列传》','廉颇知错后背负荆条向蔺相如请罪。','这次沟通失误我负荆请罪，后续流程我来补。','常用','史记,认错,合作'),
('纸上谈兵','zhi shang tan bing','只在纸面谈论用兵，比喻空谈理论不能解决实际问题。','《史记·廉颇蔺相如列传》','赵括熟读兵书却缺少实战，长平之战惨败。','架构设计不能纸上谈兵，要有压测数据。','常用','史记,实践,军事'),
('破釜沉舟','po fu chen zhou','打破锅、沉掉船，比喻下定决心，不留退路。','《史记·项羽本纪》','项羽渡河后毁船破釜，激励士兵决战。','这次创业他破釜沉舟，全职投入项目。','常用','史记,决心,楚汉'),
('卧薪尝胆','wo xin chang dan','睡柴草、尝苦胆，比喻刻苦自励，发愤图强。','《史记·越王勾践世家》','越王勾践战败后忍辱负重，时时尝胆提醒自己。','团队卧薪尝胆半年，终于把产品打磨出来。','常用','史记,励志,越王'),
('围魏救赵','wei wei jiu zhao','围攻魏国都城以解赵国之围，比喻避实击虚。','《史记·孙子吴起列传》','孙膑不直接救赵，而攻魏都迫使魏军回援。','处理瓶颈时围魏救赵，先优化上游缓存。','常用','兵法,策略,战国'),
('草木皆兵','cao mu jie bing','把草木都看成敌兵，形容惊恐疑惧。','《晋书·苻坚载记》','淝水之战后，前秦军队惊慌，把山上草木看作晋兵。','系统刚恢复，大家草木皆兵，任何告警都很紧张。','常用','晋书,心理,战争'),
('风声鹤唳','feng sheng he li','听到风声和鹤叫都以为追兵来了，形容惊慌失措。','《晋书·谢玄传》','淝水败兵逃亡途中听到风鹤之声也以为晋军追来。','一次宕机后，全组有些风声鹤唳。','常用','晋书,战争,心理'),
('投笔从戎','tou bi cong rong','扔下笔参军，比喻文人从军或转向报国事业。','《后汉书·班超传》','班超不甘久做抄写小吏，弃笔从军建功西域。','他从研究岗位投笔从戎，加入一线工程团队。','常用','后汉书,选择,志向'),
('老马识途','lao ma shi tu','老马认识道路，比喻有经验的人熟悉情况。','《韩非子·说林上》','管仲随齐桓公迷路，用老马带路走出困境。','上线流程让老同事把关，老马识途更稳。','常用','经验,韩非子,管理'),
('管鲍之交','guan bao zhi jiao','管仲和鲍叔牙的深厚友情，比喻知心朋友。','《史记·管晏列传》','鲍叔牙理解管仲处境并举荐其为相，成就齐国霸业。','他们多年互相信任，称得上管鲍之交。','常用','友情,史记,齐国'),
('一鸣惊人','yi ming jing ren','一叫就使人震惊，比喻平时不显露，一下做出惊人成绩。','《史记·滑稽列传》','楚庄王以三年不飞不鸣自喻，随后整顿朝政。','这个新人第一次发布就一鸣惊人。','常用','史记,成长,表现'),
('惊弓之鸟','jing gong zhi niao','被弓箭吓过的鸟，比喻受过惊吓后遇事害怕。','《战国策·楚策四》','更羸凭经验判断大雁受伤，虚拉弓弦便使其坠落。','经历过数据丢失后，他对备份成了惊弓之鸟。','常用','战国,心理,经验'),
('东施效颦','dong shi xiao pin','丑女模仿美女皱眉，反而更丑，比喻盲目模仿。','《庄子·天运》','东施见西施皱眉显美，跟着模仿却适得其反。','设计不能东施效颦，要适合自己的用户。','常用','庄子,模仿,审美'),
('愚公移山','yu gong yi shan','比喻坚持不懈地改造困难。','《列子·汤问》','愚公率家人挖山不止，感动天帝移走两山。','长期补数据看似慢，但愚公移山终会见效。','常用','寓言,坚持,列子'),
('精卫填海','jing wei tian hai','比喻意志坚决，不畏艰难。','《山海经·北山经》','炎帝之女化为精卫鸟，衔石木填海。','他做公益多年，有精卫填海般的执着。','常用','神话,坚持,山海经'),
('夸父逐日','kua fu zhu ri','比喻有宏大志向，也可指不自量力。','《山海经·海外北经》','夸父追逐太阳，渴死后手杖化为桃林。','探索未知需要夸父逐日的勇气，也要评估边界。','常用','神话,志向,山海经'),
('开天辟地','kai tian pi di','古代神话中盘古开辟天地，后比喻前所未有的创举。','中国古代盘古神话','盘古在混沌中分开天地，创造世界秩序。','这项技术对行业有开天辟地的意义。','常用','神话,创始,宏大'),
('女娲补天','nu wa bu tian','比喻补救巨大灾难或完成艰巨修复。','《淮南子·览冥训》','女娲炼五色石修补天裂，平息灾祸。','修复核心链路像女娲补天，需要谨慎验证。','常用','神话,补救,淮南子'),
('指鹿为马','zhi lu wei ma','指着鹿说是马，比喻故意颠倒黑白。','《史记·秦始皇本纪》','赵高献鹿称马，借此试探群臣是否顺从。','明明是故障却说是特性，近乎指鹿为马。','常用','史记,权谋,真伪'),
('朝三暮四','zhao san mu si','原指名实未变而愚弄别人，后多指反复无常。','《庄子·齐物论》','养猴人改变早晚橡子数量，猴子因表面变化而喜怒。','需求朝三暮四，开发节奏很难稳定。','常用','庄子,变化,决策'),
('对牛弹琴','dui niu tan qin','对牛弹琴，比喻对不懂道理的人讲高深道理白费力气。','汉代牟融相关故事','公明仪给牛弹高雅琴曲，牛听不懂。','给非技术用户讲底层协议，可能是对牛弹琴。','常用','沟通,对象,比喻'),
('黔驴技穷','qian lv ji qiong','比喻有限的本领已经用尽。','唐代柳宗元《黔之驴》','老虎起初害怕驴，发现驴只会叫和踢，最终吃掉它。','竞品只会降价，已经黔驴技穷。','常用','寓言,能力,柳宗元'),
('塞翁失马','sai weng shi ma','比喻祸福相互转化，坏事可能变成好事。','《淮南子·人间训》','边塞老人丢马又得马，儿子摔伤反避兵役。','这次失败让我们发现漏洞，也算塞翁失马。','常用','哲理,祸福,淮南子'),
('杞人忧天','qi ren you tian','比喻不必要的忧虑。','《列子·天瑞》','杞国人担心天会塌地会陷，寝食难安。','没有证据就担心全部服务崩溃，是杞人忧天。','常用','寓言,忧虑,列子'),
('鹬蚌相争','yu bang xiang zheng','双方相持不下，使第三者得利。','《战国策·燕策二》','鹬啄蚌肉，蚌夹鹬嘴，渔人趁机一并捕获。','两个团队争资源，最后外部竞品得利，真是鹬蚌相争。','常用','寓言,竞争,战国'),
('螳螂捕蝉','tang lang bu chan','只顾眼前利益而不知后患。','《庄子·山木》及相关古代故事','螳螂捕蝉时不知黄雀在后，黄雀也不知弹弓将至。','只看短期增长，可能陷入螳螂捕蝉的局面。','常用','寓言,风险,庄子'),
('囫囵吞枣','hu lun tun zao','把枣整个吞下，比喻学习不加分析理解。','宋代理学语录故事','有人听说梨枣功效后不细分，索性整颗吞枣。','读源码不能囫囵吞枣，要画出数据流。','常用','学习,理解,方法'),
('水滴石穿','shui di shi chuan','水不断滴落能穿透石头，比喻坚持能成事。','宋代罗大经《鹤林玉露》','张乖崖以水滴穿石说明小恶积累也会成大患。','每天补十条数据，水滴石穿很快就有规模。','常用','坚持,积累,宋代'),
('铁杵成针','tie chu cheng zhen','铁棒磨成针，比喻只要有恒心就能成功。','宋代祝穆《方舆胜览》','李白少年遇老妇磨铁杵，受启发发奋读书。','练习写代码也要铁杵成针。','常用','励志,学习,李白'),
('闻鸡起舞','wen ji qi wu','听到鸡叫就起身练剑，比喻有志者及时奋发。','《晋书·祖逖传》','祖逖和刘琨半夜闻鸡鸣便起床练武。','他每天清晨学习，有闻鸡起舞的劲头。','常用','晋书,勤奋,志向'),
('凿壁偷光','zao bi tou guang','凿穿墙壁借邻家灯光读书，比喻勤学苦读。','《西京杂记》','匡衡家贫无灯，凿壁借光读书。','资源少也能凿壁偷光，把基础补起来。','常用','学习,勤奋,匡衡'),
('悬梁刺股','xuan liang ci gu','用悬梁和刺股防止困倦，比喻刻苦学习。','《太平御览》等汇集苏秦孙敬故事','孙敬悬梁、苏秦刺股，以痛感提醒自己读书。','备考阶段他悬梁刺股，终于通过考试。','常用','学习,勤奋,典故'),
('程门立雪','cheng men li xue','站在程颐门前雪中等候，比喻尊师重道。','《宋史·杨时传》','杨时拜访程颐，见老师休息便在雪中静候。','向前辈请教要有程门立雪的态度。','常用','尊师,宋史,学习'),
('囊萤映雪','nang ying ying xue','用萤火和雪光读书，比喻家贫而勤学。','《晋书·车胤传》《孙氏世录》相关故事','车胤聚萤照书，孙康借雪光读书。','条件有限时仍能囊萤映雪，靠自驱补课。','常用','学习,勤奋,晋代'),
('韦编三绝','wei bian san jue','编连竹简的皮绳多次断开，比喻读书勤奋。','《史记·孔子世家》','孔子晚年读《易》，翻阅太多使韦编多次断裂。','核心文档要反复读到韦编三绝。','常用','读书,孔子,史记'),
('洛阳纸贵','luo yang zhi gui','文章流传很广，连纸价都上涨。','《晋书·左思传》','左思写成《三都赋》，众人争相传抄，洛阳纸价上涨。','这篇教程写得太好，发布后洛阳纸贵。','常用','文学,传播,晋书'),
('江郎才尽','jiang lang cai jin','比喻才思衰退。','《南史·江淹传》','江淹梦中归还彩笔后，文才不如从前。','长期不学习，再有天赋也可能江郎才尽。','常用','文学,才华,南史'),
('才高八斗','cai gao ba dou','形容文才极高。','南朝宋无名氏《释常谈》相关记载','谢灵运称天下才一石，曹子建独占八斗。','他的技术文章才高八斗，深入又好读。','常用','文学,才华,称赞'),
('高山流水','gao shan liu shui','比喻知音难遇或乐曲高妙。','《列子·汤问》','伯牙弹琴，钟子期能听出高山流水之意。','真正理解产品愿景的人，是高山流水般的知音。','常用','知音,音乐,列子'),
('四面楚歌','si mian chu ge','四面都传来楚歌，比喻陷入孤立危急境地。','《史记·项羽本纪》','项羽被围垓下，听到四面楚歌，以为楚地尽失。','资金、用户、技术都出问题，公司一时四面楚歌。','常用','楚汉,困境,史记'),
('暗度陈仓','an du chen cang','表面迷惑对方，暗中采取真实行动。','《史记·高祖本纪》相关楚汉故事','韩信明修栈道迷惑项羽，暗中从陈仓出兵。','这次竞争策略是明修栈道，暗度陈仓。','常用','楚汉,策略,兵法'),
('背水一战','bei shui yi zhan','背靠河水决战，比喻处于绝境而奋力一搏。','《史记·淮阴侯列传》','韩信让军队背水列阵，迫使士兵拼死作战。','发布窗口只剩一次，团队背水一战。','常用','楚汉,决战,史记'),
('项庄舞剑','xiang zhuang wu jian','比喻说话或行动另有真实意图。','《史记·项羽本纪》','鸿门宴上项庄舞剑，意在刺杀刘邦。','他表面提建议，其实项庄舞剑，想推动换方案。','常用','楚汉,权谋,史记'),
('多多益善','duo duo yi shan','越多越好。','《史记·淮阴侯列传》','刘邦问韩信能带多少兵，韩信说自己带兵多多益善。','优质测试样例当然多多益善。','常用','史记,能力,数量'),
('退避三舍','tui bi san she','主动退让九十里，比喻让步或回避冲突。','《左传·僖公二十三年》','晋文公遵守旧诺，与楚军交战前退避三舍。','这次争论先退避三舍，等数据出来再定。','常用','左传,让步,春秋'),
('一鼓作气','yi gu zuo qi','第一次击鼓时士气最盛，比喻趁劲头足时完成事情。','《左传·庄公十年》','曹刿认为作战要在士气最旺时出击。','今天状态好，一鼓作气把 MVP 做出来。','常用','左传,士气,行动'),
('唇亡齿寒','chun wang chi han','嘴唇没了牙齿会冷，比喻关系密切，利害相关。','《左传·僖公五年》','虢国灭亡后虞国也难保，宫之奇以唇齿关系进谏。','上下游服务唇亡齿寒，不能只看单点指标。','常用','左传,关系,风险'),
('假途灭虢','jia tu mie guo','借道去灭虢，后也指以借路为名达到别的目的。','《左传·僖公五年》','晋国向虞国借路攻虢，最终连虞国也灭掉。','合作方案要警惕假途灭虢式风险。','较少见','左传,策略,春秋'),
('讳疾忌医','hui ji ji yi','隐瞒疾病，不愿医治，比喻掩饰缺点错误。','《韩非子·喻老》','扁鹊多次提醒蔡桓公病情，桓公不听终至不可救。','系统有隐患不能讳疾忌医。','常用','韩非子,错误,健康'),
('病入膏肓','bing ru gao huang','病到了膏和肓之间，形容病情严重难治。','《左传·成公十年》','晋景公梦见疾病藏在膏肓之间，医者认为难治。','债务堆到病入膏肓，重构成本会非常高。','常用','左传,风险,健康'),
('盲人摸象','mang ren mo xiang','比喻只凭局部了解就妄下整体判断。','佛教譬喻故事','几个盲人分别摸象不同部位，各执一词。','只看一条日志就断言根因，是盲人摸象。','常用','认知,局部,判断'),
('画龙点睛','hua long dian jing','比喻在关键处加上一笔，使整体生动有神。','唐代张彦远《历代名画记》','张僧繇画龙不点睛，点睛后龙破壁飞去。','这个标题为整篇文档画龙点睛。','常用','艺术,关键,表达'),
('望梅止渴','wang mei zhi ke','用想象梅子的酸味止渴，比喻用空想安慰自己。','《世说新语·假谲》','曹操行军途中说前方有梅林，士兵口生津液缓解口渴。','只画愿景不解决问题，最多望梅止渴。','常用','三国,心理,激励'),
('七步成诗','qi bu cheng shi','七步内作成诗，比喻才思敏捷。','《世说新语·文学》','曹丕令曹植七步作诗，曹植写下煮豆相煎之意。','他现场写方案，几乎七步成诗。','常用','文学,才思,三国'),
('煮豆燃萁','zhu dou ran qi','用豆秸煮豆，比喻兄弟相残。','《世说新语·文学》','曹植以豆和豆萁同根相煎，表达兄弟相逼之痛。','同团队互相消耗，无异于煮豆燃萁。','常用','三国,亲情,冲突'),
('乐不思蜀','le bu si shu','快乐得不再思念蜀国，比喻安于享乐忘本。','《三国志·蜀书·后主传》裴注','刘禅亡国后在洛阳作乐，说不思念蜀地。','不能因为短期成绩就乐不思蜀。','常用','三国,享乐,警醒'),
('鞠躬尽瘁','ju gong jin cui','恭敬谨慎，竭尽心力。','诸葛亮《后出师表》','诸葛亮以鞠躬尽瘁、死而后已表达报国之志。','他为这个项目鞠躬尽瘁，细节都亲自跟进。','常用','三国,责任,诸葛亮'),
('初出茅庐','chu chu mao lu','刚离开草庐，比喻刚参加工作或初露头角。','《三国演义》相关诸葛亮故事','诸葛亮出山后初次用兵，逐渐显露才干。','初出茅庐也没关系，保持学习就能成长。','常用','三国,新人,成长'),
('草船借箭','cao chuan jie jian','比喻运用智谋借助外力达到目的。','《三国演义》','诸葛亮利用大雾和草船，引曹军放箭获得箭矢。','他用开源工具草船借箭，快速完成原型。','常用','三国,智谋,借力'),
('三人成虎','san ren cheng hu','三个人说城里有虎，听者就信了，比喻谣言重复会让人信以为真。','《战国策·魏策二》','庞葱用三人成虎劝魏王不要轻信谗言。','微信群里的消息三人成虎，仍要查证。','常用','战国,谣言,判断'),
('曾参杀人','zeng shen sha ren','比喻流言多次传播会使亲近者也怀疑。','《战国策·秦策二》','有人诬称曾参杀人，传言多次后其母也惊疑逃避。','再可靠的人也可能被曾参杀人的流言伤害。','较少见','战国,流言,信任'),
('众口铄金','zhong kou shuo jin','众人的言论能熔化金属，比喻舆论力量巨大。','《国语·周语下》','古人以众口之力比喻流言和舆论足以改变人心。','众口铄金，公开说明必须及时准确。','常用','舆论,国语,传播'),
('门可罗雀','men ke luo que','门前冷落得可以张网捕雀，形容宾客稀少。','《史记·汲郑列传》','翟公失势后门庭冷落，门前可设网捕雀。','活动结束后页面访问门可罗雀。','常用','史记,冷清,对比'),
('门庭若市','men ting ruo shi','门前和院子像集市一样热闹，形容来客很多。','《战国策·齐策一》','邹忌讽齐王纳谏后，进谏者络绎不绝。','新品发布当天，展台门庭若市。','常用','热闹,战国,场景'),
('车水马龙','che shui ma long','车像流水，马像游龙，形容往来热闹。','《后汉书·明德马皇后纪》','马皇后形容外戚门前车马繁盛。','节日期间商业街车水马龙。','常用','热闹,后汉书,城市'),
('一字千金','yi zi qian jin','一个字价值千金，形容文章精妙或文字价值高。','《史记·吕不韦列传》','吕不韦公布《吕氏春秋》，称能改一字赏千金。','这句产品 slogan 真是一字千金。','常用','史记,文字,价值'),
('千金买骨','qian jin mai gu','比喻重视人才，真心求贤。','《战国策·燕策一》','郭隗讲古人千金买千里马骨，表示诚意可招来真马。','公司千金买骨，先用诚意吸引核心人才。','较少见','战国,人才,诚意'),
('伯乐相马','bo le xiang ma','比喻善于发现和识别人才。','《战国策》及韩愈《马说》相关典故','伯乐善于识别千里马，后用来比喻识才之人。','优秀导师要有伯乐相马的眼光。','常用','人才,识别,比喻'),
('汗牛充栋','han niu chong dong','书多得运输时牛出汗，收藏时堆满屋子，形容书籍极多。','唐代柳宗元《陆文通先生墓表》','柳宗元形容藏书繁富，搬运和存放都极多。','这类资料汗牛充栋，要先筛重点。','常用','读书,数量,柳宗元'),
('开卷有益','kai juan you yi','打开书本总有好处，劝人读书。','宋代王辟之《渑水燕谈录》','宋太宗勤读《太平御览》，认为开卷总有收获。','每天读一点技术文档，开卷有益。','常用','读书,学习,宋代'),
('按图索骥','an tu suo ji','照图寻找好马，比喻拘泥线索机械办事，也指按线索寻找。','《汉书·梅福传》相关后世故事','伯乐之子按相马图找马，因死板而闹笑话。','排查问题可以按图索骥，但不能忽略现场变化。','常用','方法,线索,机械'),
('一丘之貉','yi qiu zhi he','同一山丘上的貉，比喻彼此一样，都是坏人或同类。','《汉书·杨恽传》','杨恽以一丘之貉讥讽古今小人同类。','这几个刷量账号手法相同，几乎一丘之貉。','常用','讽刺,汉书,同类'),
('华而不实','hua er bu shi','外表好看而内容空虚。','《左传·文公五年》','古人以花而不结果比喻徒有外表。','只做漂亮页面却不能使用，就是华而不实。','常用','评价,左传,质量'),
('曲高和寡','qu gao he gua','曲调越高，能跟着唱的人越少，比喻言论作品高深而知音少。','宋玉《对楚王问》','宋玉解释歌曲越高雅，能应和的人越少。','这篇论文曲高和寡，需要配入门解读。','常用','艺术,知音,表达'),
